from flask import Flask, request, send_from_directory, jsonify, abort
import os

app = Flask(__name__)

# Define the root directory for file operations
ROOT_DIR = os.path.abspath("user_files")

def secure_path(user_path):
    # Normalize the path to prevent path traversal
    normalized_path = os.path.normpath(user_path)
    # Construct the full path
    full_path = os.path.join(ROOT_DIR, normalized_path)
    # Ensure the path is within the root directory
    if not full_path.startswith(ROOT_DIR):
        abort(403, "Access denied")
    return full_path

@app.route('/list', methods=['GET'])
def list_directory():
    user_path = request.args.get('path', '')
    full_path = secure_path(user_path)
    if not os.path.isdir(full_path):
        abort(404, "Directory not found")
    files = os.listdir(full_path)
    return jsonify(files)

@app.route('/download', methods=['GET'])
def download_file():
    user_path = request.args.get('path', '')
    full_path = secure_path(user_path)
    if not os.path.isfile(full_path):
        abort(404, "File not found")
    directory = os.path.dirname(full_path)
    filename = os.path.basename(full_path)
    return send_from_directory(directory, filename, as_attachment=True)

@app.route('/info', methods=['GET'])
def file_info():
    user_path = request.args.get('path', '')
    full_path = secure_path(user_path)
    if not os.path.exists(full_path):
        abort(404, "File or directory not found")
    info = {
        'path': user_path,
        'is_file': os.path.isfile(full_path),
        'is_directory': os.path.isdir(full_path),
        'size': os.path.getsize(full_path) if os.path.isfile(full_path) else None
    }
    return jsonify(info)

if __name__ == '__main__':
    app.run(debug=True)